&lt;ul&gt;
	&lt;li style=&quot;user-select: text !important;&quot;&gt;&lt;span style=&quot;font-weight: 700; user-select: text !important;&quot;&gt;List of Important Days/Events in March:​&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

